INSERT INTO public.questions VALUES ('cmo50cdsx000154lri94vk1iy', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quel est le principal objectif de la charte de projet ?', '[{"text": "Definir le budget du projet", "label": "A"}, {"text": "Autoriser formellement le projet", "label": "B"}, {"text": "Identifier les parties prenantes", "label": "C"}, {"text": "Planifier les activites", "label": "D"}]', 'B', 'La charte de projet autorise formellement l''existence du projet et donne au chef de projet l''autorite d''utiliser les ressources', NULL, 'medium', 1, 0, '2026-04-19 00:08:14.817', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdte000254lrkkuwmzc4', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Dans le cadre de la gestion des risques, qu''est-ce qu''un risque residuel ?', '[{"text": "Un risque non identifie", "label": "A"}, {"text": "Un risque qui subsiste apres la mise en oeuvre des reponses", "label": "B"}, {"text": "Un risque secondaire", "label": "C"}, {"text": "Un risque positif", "label": "D"}]', 'B', 'Un risque residuel est celui qui reste apres avoir applique les strategies de reponse aux risques', NULL, 'medium', 1, 1, '2026-04-19 00:08:14.834', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdto000354lrd6yuqbvy', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quelle technique est utilisee pour estimer la duree d''une activite basee sur des projets similaires ?', '[{"text": "Estimation par analogie", "label": "A"}, {"text": "Estimation parametrique", "label": "B"}, {"text": "Estimation a trois points", "label": "C"}, {"text": "Estimation ascendante", "label": "D"}]', 'A', 'L''estimation par analogie utilise les donnees historiques de projets similaires pour estimer', NULL, 'easy', 1, 2, '2026-04-19 00:08:14.844', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdtz000454lrdlixav10', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quel est le role du sponsor du projet ?', '[{"text": "Gerer les activites quotidiennes", "label": "A"}, {"text": "Fournir les ressources et le soutien au projet", "label": "B"}, {"text": "Executer les taches du projet", "label": "C"}, {"text": "Tester les livrables", "label": "D"}]', 'B', 'Le sponsor fournit les ressources financieres, resout les conflits escales et soutient le chef de projet', NULL, 'easy', 1, 3, '2026-04-19 00:08:14.855', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdu6000554lrv1gmt6dc', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Qu''est-ce que le chemin critique dans un projet ?', '[{"text": "Le chemin le plus court du projet", "label": "A"}, {"text": "La sequence d''activites la plus longue determinant la duree minimale du projet", "label": "B"}, {"text": "Le chemin avec le plus de ressources", "label": "C"}, {"text": "Le chemin le plus couteux", "label": "D"}]', 'B', 'Le chemin critique est la plus longue sequence d''activites dependantes qui determine la duree totale du projet', NULL, 'medium', 1, 4, '2026-04-19 00:08:14.862', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdue000654lrgear00bx', NULL, 'cmo50cdsd000054lr6i5rtypu', 'TRUE_FALSE', 'Le WBS (Work Breakdown Structure) decompose le travail du projet en elements plus petits et plus faciles a gerer.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'Le WBS est une decomposition hierarchique du travail total a effectuer par l''equipe projet', NULL, 'easy', 1, 5, '2026-04-19 00:08:14.87', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdun000754lrb4bonauq', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quelle est la formule de l''indice de performance des couts (CPI) ?', '[{"text": "CPI = EV / AC", "label": "A"}, {"text": "CPI = AC / EV", "label": "B"}, {"text": "CPI = PV / AC", "label": "C"}, {"text": "CPI = EV / PV", "label": "D"}]', 'A', 'CPI = Earned Value / Actual Cost. Un CPI > 1 indique un projet en dessous du budget', NULL, 'hard', 1, 6, '2026-04-19 00:08:14.879', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cduw000854lrkxwh0icd', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quel processus appartient au groupe de processus de cloture ?', '[{"text": "Valider le contenu", "label": "A"}, {"text": "Clore le projet ou la phase", "label": "B"}, {"text": "Maitriser le calendrier", "label": "C"}, {"text": "Gerer les communications", "label": "D"}]', 'B', 'Clore le projet ou la phase est le processus de finalisation de toutes les activites de tous les groupes de processus', NULL, 'medium', 1, 7, '2026-04-19 00:08:14.888', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdv5000954lr5hyhcfpy', NULL, 'cmo50cdsd000054lr6i5rtypu', 'MULTIPLE_CHOICE', 'Quels sont des outils de gestion de la qualite ? (Selectionnez toutes les bonnes reponses)', '[{"text": "Diagramme de Pareto", "label": "A"}, {"text": "Diagramme d''Ishikawa", "label": "B"}, {"text": "Diagramme de Gantt", "label": "C"}, {"text": "Histogramme", "label": "D"}]', 'A,B,D', 'Le diagramme de Pareto, d''Ishikawa et l''histogramme sont des outils qualite. Le Gantt est un outil de planification', NULL, 'hard', 1, 8, '2026-04-19 00:08:14.897', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdvb000a54lrtdgnz6xk', NULL, 'cmo50cdsd000054lr6i5rtypu', 'SINGLE_CHOICE', 'Quelle strategie de reponse aux risques negatifs consiste a eliminer completement la menace ?', '[{"text": "Attenuer", "label": "A"}, {"text": "Transferer", "label": "B"}, {"text": "Eviter", "label": "C"}, {"text": "Accepter", "label": "D"}]', 'C', 'Eviter un risque signifie modifier le plan de projet pour eliminer completement la menace', NULL, 'medium', 1, 9, '2026-04-19 00:08:14.903', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdvv000c54lrf049evww', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Combien de domaines de connaissance sont definis dans le PMBOK Guide ?', '[{"text": "8", "label": "A"}, {"text": "10", "label": "B"}, {"text": "12", "label": "C"}, {"text": "5", "label": "D"}]', 'B', 'Le PMBOK Guide definit 10 domaines de connaissance en gestion de projet', NULL, 'easy', 1, 0, '2026-04-19 00:08:14.923', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdw2000d54lrw6tsd8my', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Quel groupe de processus vient apres l''initiation ?', '[{"text": "Execution", "label": "A"}, {"text": "Surveillance et maitrise", "label": "B"}, {"text": "Planification", "label": "C"}, {"text": "Cloture", "label": "D"}]', 'C', 'L''ordre est : Initiation, Planification, Execution, Surveillance et maitrise, Cloture', NULL, 'easy', 1, 1, '2026-04-19 00:08:14.93', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdw8000e54lri1cb4660', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'TRUE_FALSE', 'Un projet est un effort temporaire entrepris pour creer un produit, service ou resultat unique.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'C''est la definition exacte d''un projet selon le PMI', NULL, 'easy', 1, 2, '2026-04-19 00:08:14.936', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdwe000f54lrb2xjri7o', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Qui est responsable de la gestion quotidienne du projet ?', '[{"text": "Le sponsor", "label": "A"}, {"text": "Le chef de projet", "label": "B"}, {"text": "Le client", "label": "C"}, {"text": "Le PMO", "label": "D"}]', 'B', 'Le chef de projet est responsable de la gestion quotidienne et de l''atteinte des objectifs', NULL, 'easy', 1, 3, '2026-04-19 00:08:14.942', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdwl000g54lrglv8gsog', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Qu''est-ce qu''un livrable dans un projet ?', '[{"text": "Un budget", "label": "A"}, {"text": "Un produit, resultat ou service mesurable et verifiable", "label": "B"}, {"text": "Un risque", "label": "C"}, {"text": "Une reunion", "label": "D"}]', 'B', 'Un livrable est tout produit, resultat ou capacite unique et verifiable qui doit etre produit pour achever un processus', NULL, 'easy', 1, 4, '2026-04-19 00:08:14.949', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdws000h54lrmhdun0hj', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Le triangle de contraintes du projet inclut :', '[{"text": "Cout, temps, qualite", "label": "A"}, {"text": "Risque, communication, approvisionnement", "label": "B"}, {"text": "Portee, calendrier, cout", "label": "C"}, {"text": "Equipe, sponsor, client", "label": "D"}]', 'C', 'Le triple contrainte traditionnel est : portee (scope), calendrier (schedule) et cout (cost)', NULL, 'medium', 1, 5, '2026-04-19 00:08:14.957', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdwz000i54lr9lo6ue2u', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'SINGLE_CHOICE', 'Qu''est-ce qu''une partie prenante (stakeholder) ?', '[{"text": "Uniquement le client", "label": "A"}, {"text": "Toute personne ou organisation affectee par le projet", "label": "B"}, {"text": "Uniquement l''equipe projet", "label": "C"}, {"text": "Le sponsor", "label": "D"}]', 'B', 'Une partie prenante est tout individu, groupe ou organisation pouvant affecter ou etre affecte par le projet', NULL, 'easy', 1, 6, '2026-04-19 00:08:14.963', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdx5000j54lrgbxm079b', NULL, 'cmo50cdvn000b54lrvbo6ii4q', 'TRUE_FALSE', 'La planification est un processus qui se fait une seule fois au debut du projet.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'B', 'La planification est iterative et se fait tout au long du projet (elaboration progressive)', NULL, 'medium', 1, 7, '2026-04-19 00:08:14.969', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdxn000l54lr1w0ughn3', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'SINGLE_CHOICE', 'Quelle est la difference principale entre un programme et un projet ?', '[{"text": "Le budget", "label": "A"}, {"text": "Un programme est un groupe de projets geres de maniere coordonnee pour des benefices qu''on ne pourrait pas obtenir individuellement", "label": "B"}, {"text": "La duree", "label": "C"}, {"text": "Le nombre de personnes", "label": "D"}]', 'B', 'Un programme coordonne plusieurs projets pour obtenir des benefices strategiques', NULL, 'medium', 1, 0, '2026-04-19 00:08:14.987', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdxv000m54lrkdxodwof', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'SINGLE_CHOICE', 'Quel est le principal objectif de la gouvernance de programme ?', '[{"text": "Reduire les couts", "label": "A"}, {"text": "Assurer l''alignement strategique et la livraison des benefices", "label": "B"}, {"text": "Gerer les risques", "label": "C"}, {"text": "Planifier les ressources", "label": "D"}]', 'B', 'La gouvernance de programme assure que le programme reste aligne avec la strategie organisationnelle', NULL, 'hard', 1, 1, '2026-04-19 00:08:14.995', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdy0000n54lryws5d1w4', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'TRUE_FALSE', 'Un programme a toujours une date de fin definie comme un projet.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'B', 'Un programme peut etre continu tant qu''il delivre des benefices a l''organisation', NULL, 'medium', 1, 2, '2026-04-19 00:08:15', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdy6000o54lrmfyhe2qg', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'SINGLE_CHOICE', 'Qui est le responsable ultime du succes d''un programme ?', '[{"text": "Le chef de projet", "label": "A"}, {"text": "Le directeur de programme", "label": "B"}, {"text": "Le sponsor du programme", "label": "C"}, {"text": "Le PMO", "label": "D"}]', 'B', 'Le directeur de programme est responsable de la coordination et du succes global du programme', NULL, 'medium', 1, 3, '2026-04-19 00:08:15.006', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdyi000p54lrxi78rthp', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'SINGLE_CHOICE', 'La gestion des benefices dans un programme concerne :', '[{"text": "Le calcul du ROI", "label": "A"}, {"text": "L''identification, la planification, la livraison et le maintien des benefices", "label": "B"}, {"text": "La gestion budgetaire", "label": "C"}, {"text": "La satisfaction client", "label": "D"}]', 'B', 'La gestion des benefices couvre tout le cycle de vie des benefices du programme', NULL, 'hard', 1, 4, '2026-04-19 00:08:15.018', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdyr000q54lrb4a445qj', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'SINGLE_CHOICE', 'Qu''est-ce qu''un composant de programme ?', '[{"text": "Un budget", "label": "A"}, {"text": "Un projet, sous-programme ou activite connexe au sein du programme", "label": "B"}, {"text": "Un risque", "label": "C"}, {"text": "Un livrable", "label": "D"}]', 'B', 'Les composants d''un programme sont les projets, sous-programmes et activites qui le constituent', NULL, 'easy', 1, 5, '2026-04-19 00:08:15.027', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdyx000r54lrisgsojq7', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'MULTIPLE_CHOICE', 'Quels sont des domaines de performance de la gestion de programme ?', '[{"text": "Alignement strategique", "label": "A"}, {"text": "Gestion des benefices", "label": "B"}, {"text": "Gestion de la qualite", "label": "C"}, {"text": "Engagement des parties prenantes", "label": "D"}]', 'A,B,D', 'L''alignement strategique, la gestion des benefices et l''engagement des parties prenantes sont des domaines cles', NULL, 'hard', 1, 6, '2026-04-19 00:08:15.033', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdz3000s54lrki7r7ik3', NULL, 'cmo50cdxe000k54lrtvsal6bq', 'TRUE_FALSE', 'Le directeur de programme doit avoir des competences en leadership et en pensee strategique.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'Le leadership et la pensee strategique sont essentiels pour diriger un programme', NULL, 'easy', 1, 7, '2026-04-19 00:08:15.039', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdzp000u54lrrxjcoqhh', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'Quelle est la premiere etape du processus de gestion des risques ?', '[{"text": "Analyse qualitative", "label": "A"}, {"text": "Identification des risques", "label": "B"}, {"text": "Planification de la gestion des risques", "label": "C"}, {"text": "Reponse aux risques", "label": "D"}]', 'C', 'La planification definit comment les activites de gestion des risques seront menees', NULL, 'medium', 1, 0, '2026-04-19 00:08:15.061', true, '{}');
INSERT INTO public.questions VALUES ('cmo50cdzv000v54lrcea7j54z', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'La matrice de probabilite et d''impact est utilisee lors de :', '[{"text": "L''identification des risques", "label": "A"}, {"text": "L''analyse qualitative des risques", "label": "B"}, {"text": "L''analyse quantitative des risques", "label": "C"}, {"text": "La planification des reponses", "label": "D"}]', 'B', 'La matrice probabilite/impact est un outil d''analyse qualitative pour prioriser les risques', NULL, 'medium', 1, 1, '2026-04-19 00:08:15.067', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce02000w54lrovm8n853', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'La valeur monetaire attendue (EMV) se calcule par :', '[{"text": "Probabilite + Impact", "label": "A"}, {"text": "Probabilite x Impact", "label": "B"}, {"text": "Impact / Probabilite", "label": "C"}, {"text": "Probabilite - Impact", "label": "D"}]', 'B', 'EMV = Probabilite x Impact monetaire. C''est utilise dans l''analyse quantitative', NULL, 'hard', 1, 2, '2026-04-19 00:08:15.074', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce08000x54lrx2m50zle', NULL, 'cmo50cdzi000t54lrqvqboycu', 'TRUE_FALSE', 'Un risque peut etre aussi bien une menace qu''une opportunite.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'Les risques positifs (opportunites) et negatifs (menaces) doivent etre geres', NULL, 'easy', 1, 3, '2026-04-19 00:08:15.08', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce0g000y54lrv2qmbu85', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'Quelle technique consiste a accepter un risque et a prevoir un budget de reserve ?', '[{"text": "Evitement", "label": "A"}, {"text": "Transfert", "label": "B"}, {"text": "Acceptation active", "label": "C"}, {"text": "Attenuation", "label": "D"}]', 'C', 'L''acceptation active implique de constituer une reserve de contingence', NULL, 'medium', 1, 4, '2026-04-19 00:08:15.088', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce0p000z54lr6s6qgo6a', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'Le registre des risques contient :', '[{"text": "Uniquement les risques negatifs", "label": "A"}, {"text": "Les risques identifies, leur analyse et les reponses planifiees", "label": "B"}, {"text": "Le budget du projet", "label": "C"}, {"text": "Le calendrier", "label": "D"}]', 'B', 'Le registre des risques est le document central contenant toutes les informations sur les risques', NULL, 'easy', 1, 5, '2026-04-19 00:08:15.097', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce0v001054lr97aitjaa', NULL, 'cmo50cdzi000t54lrqvqboycu', 'MULTIPLE_CHOICE', 'Quelles sont des techniques d''identification des risques ?', '[{"text": "Brainstorming", "label": "A"}, {"text": "Analyse SWOT", "label": "B"}, {"text": "Diagramme de Gantt", "label": "C"}, {"text": "Technique Delphi", "label": "D"}]', 'A,B,D', 'Le brainstorming, l''analyse SWOT et la technique Delphi sont des methodes d''identification des risques', NULL, 'medium', 1, 6, '2026-04-19 00:08:15.103', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce11001154lrtnj46efr', NULL, 'cmo50cdzi000t54lrqvqboycu', 'SINGLE_CHOICE', 'La simulation Monte Carlo est utilisee dans :', '[{"text": "L''identification des risques", "label": "A"}, {"text": "L''analyse qualitative", "label": "B"}, {"text": "L''analyse quantitative des risques", "label": "C"}, {"text": "La cloture du projet", "label": "D"}]', 'C', 'Monte Carlo est une technique de simulation utilisee dans l''analyse quantitative pour modeliser les incertitudes', NULL, 'hard', 1, 7, '2026-04-19 00:08:15.109', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce1k001354lr1o1jjgnl', NULL, 'cmo50ce1b001254lrgad7y6bp', 'SINGLE_CHOICE', 'Quel est l''objectif principal d''un audit de projet ?', '[{"text": "Sanctionner l''equipe", "label": "A"}, {"text": "Evaluer la conformite et identifier les ameliorations", "label": "B"}, {"text": "Reduire le budget", "label": "C"}, {"text": "Accelerer le calendrier", "label": "D"}]', 'B', 'L''audit vise a evaluer la conformite aux standards et identifier les opportunites d''amelioration', NULL, 'easy', 1, 0, '2026-04-19 00:08:15.128', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce1r001454lrvgetrmoy', NULL, 'cmo50ce1b001254lrgad7y6bp', 'TRUE_FALSE', 'Un audit interne est conduit par une entite independante exterieure a l''organisation.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'B', 'L''audit interne est conduit par des auditeurs au sein de l''organisation. L''audit externe est conduit par des entites independantes', NULL, 'easy', 1, 1, '2026-04-19 00:08:15.135', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce20001554lroqqw48om', NULL, 'cmo50ce1b001254lrgad7y6bp', 'SINGLE_CHOICE', 'Qu''est-ce qu''un point de controle (control gate) dans un projet ?', '[{"text": "Une reunion quotidienne", "label": "A"}, {"text": "Un point de decision formelle pour evaluer la progression avant de continuer", "label": "B"}, {"text": "Un test technique", "label": "C"}, {"text": "Une revue budgetaire", "label": "D"}]', 'B', 'Un point de controle est un jalon ou les decideurs evaluent si le projet doit continuer', NULL, 'medium', 1, 2, '2026-04-19 00:08:15.144', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce28001654lrg21cc59m', NULL, 'cmo50ce1b001254lrgad7y6bp', 'SINGLE_CHOICE', 'La tracabilite des exigences permet de :', '[{"text": "Reduire les couts", "label": "A"}, {"text": "S''assurer que chaque exigence est liee a un objectif et testable", "label": "B"}, {"text": "Accelerer le developpement", "label": "C"}, {"text": "Eliminer les risques", "label": "D"}]', 'B', 'La matrice de tracabilite assure que chaque exigence est justifiee, implementee et testee', NULL, 'medium', 1, 3, '2026-04-19 00:08:15.152', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce2g001754lrq0pvexk6', NULL, 'cmo50ce1b001254lrgad7y6bp', 'SINGLE_CHOICE', 'Quel document formalise les resultats d''un audit ?', '[{"text": "Le plan de projet", "label": "A"}, {"text": "Le rapport d''audit", "label": "B"}, {"text": "Le registre des risques", "label": "C"}, {"text": "Le backlog", "label": "D"}]', 'B', 'Le rapport d''audit documente les constatations, conclusions et recommandations', NULL, 'easy', 1, 4, '2026-04-19 00:08:15.161', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce2n001854lroryp3q7c', NULL, 'cmo50ce1b001254lrgad7y6bp', 'MULTIPLE_CHOICE', 'Quels elements sont generalement verifies lors d''un audit de projet ?', '[{"text": "Respect des processus", "label": "A"}, {"text": "Qualite des livrables", "label": "B"}, {"text": "Couleur du logo", "label": "C"}, {"text": "Conformite reglementaire", "label": "D"}]', 'A,B,D', 'L''audit verifie les processus, la qualite et la conformite, pas les aspects esthetiques', NULL, 'easy', 1, 5, '2026-04-19 00:08:15.167', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce2u001954lr253wm13z', NULL, 'cmo50ce1b001254lrgad7y6bp', 'SINGLE_CHOICE', 'Le controle des changements a pour but de :', '[{"text": "Bloquer tout changement", "label": "A"}, {"text": "Evaluer, approuver ou rejeter les modifications de maniere structuree", "label": "B"}, {"text": "Accelerer les modifications", "label": "C"}, {"text": "Eliminer la documentation", "label": "D"}]', 'B', 'Le controle des changements assure que les modifications sont evaluees et approuvees avant implementation', NULL, 'medium', 1, 6, '2026-04-19 00:08:15.174', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce37001a54lrugs5f0dc', NULL, 'cmo50ce1b001254lrgad7y6bp', 'TRUE_FALSE', 'Les actions correctives visent a corriger les ecarts par rapport au plan de projet.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'Les actions correctives realisent la performance future attendue du projet en corrigeant les ecarts', NULL, 'easy', 1, 7, '2026-04-19 00:08:15.187', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce45001c54lrxm3mh4pe', NULL, 'cmo50ce3h001b54lr9rccagi6', 'SINGLE_CHOICE', 'Quelle methodologie de gestion de projet est iterative et incrementale ?', '[{"text": "Waterfall", "label": "A"}, {"text": "Agile", "label": "B"}, {"text": "PRINCE2", "label": "C"}, {"text": "Lean", "label": "D"}]', 'B', 'Agile est une approche iterative et incrementale qui s''adapte aux changements', NULL, 'easy', 1, 0, '2026-04-19 00:08:15.221', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce4b001d54lr6fa24uqm', NULL, 'cmo50ce3h001b54lr9rccagi6', 'SINGLE_CHOICE', 'Dans Google Project Management, quel outil est recommande pour le suivi des taches ?', '[{"text": "Microsoft Project", "label": "A"}, {"text": "Asana ou des feuilles de calcul", "label": "B"}, {"text": "AutoCAD", "label": "C"}, {"text": "Photoshop", "label": "D"}]', 'B', 'Google recommande des outils accessibles comme Asana, Trello ou Google Sheets', NULL, 'easy', 1, 1, '2026-04-19 00:08:15.227', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce4j001e54lrsb6l6slh', NULL, 'cmo50ce3h001b54lr9rccagi6', 'TRUE_FALSE', 'La methodologie Waterfall permet des changements faciles a tout moment du projet.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'B', 'Waterfall est sequentiel et les changements sont couteux une fois une phase terminee', NULL, 'easy', 1, 2, '2026-04-19 00:08:15.235', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce4p001f54lrykogeg0z', NULL, 'cmo50ce3h001b54lr9rccagi6', 'SINGLE_CHOICE', 'Qu''est-ce qu''un OKR (Objectives and Key Results) ?', '[{"text": "Un outil budgetaire", "label": "A"}, {"text": "Un cadre de definition d''objectifs mesurables", "label": "B"}, {"text": "Un type de diagramme", "label": "C"}, {"text": "Un logiciel de gestion", "label": "D"}]', 'B', 'Les OKR definissent des objectifs ambitieux et des resultats cles mesurables pour suivre la progression', NULL, 'medium', 1, 3, '2026-04-19 00:08:15.241', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce4w001g54lrt4h2gt91', NULL, 'cmo50ce3h001b54lr9rccagi6', 'SINGLE_CHOICE', 'Quelle est la premiere chose a faire lors du demarrage d''un projet ?', '[{"text": "Commencer le developpement", "label": "A"}, {"text": "Definir les objectifs et les parties prenantes", "label": "B"}, {"text": "Embaucher l''equipe", "label": "C"}, {"text": "Creer le budget", "label": "D"}]', 'B', 'La definition des objectifs et l''identification des parties prenantes sont les premieres etapes', NULL, 'easy', 1, 4, '2026-04-19 00:08:15.248', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce53001h54lrn672bon3', NULL, 'cmo50ce3h001b54lr9rccagi6', 'SINGLE_CHOICE', 'Un retrospective en Agile sert a :', '[{"text": "Planifier le sprint suivant", "label": "A"}, {"text": "Reflechir a ce qui a bien fonctionne et ce qui peut etre ameliore", "label": "B"}, {"text": "Presenter les livrables au client", "label": "C"}, {"text": "Estimer les couts", "label": "D"}]', 'B', 'La retrospective est un moment de reflexion collective pour l''amelioration continue', NULL, 'medium', 1, 5, '2026-04-19 00:08:15.255', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce5a001i54lrhut8tdbv', NULL, 'cmo50ce3h001b54lr9rccagi6', 'MULTIPLE_CHOICE', 'Quelles sont des competences cles d''un chef de projet selon Google ?', '[{"text": "Communication", "label": "A"}, {"text": "Organisation", "label": "B"}, {"text": "Programmation avancee", "label": "C"}, {"text": "Resolution de problemes", "label": "D"}]', 'A,B,D', 'Communication, organisation et resolution de problemes sont essentiels. La programmation n''est pas requise', NULL, 'easy', 1, 6, '2026-04-19 00:08:15.262', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce5g001j54lrjv8946dl', NULL, 'cmo50ce3h001b54lr9rccagi6', 'TRUE_FALSE', 'Un chef de projet doit toujours etre un expert technique du domaine du projet.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'B', 'Un chef de projet gere les processus, le calendrier et l''equipe, pas necessairement l''expertise technique', NULL, 'easy', 1, 7, '2026-04-19 00:08:15.268', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce61001l54lr5np0cu2u', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Que signifie ITIL ?', '[{"text": "International Technology Infrastructure Library", "label": "A"}, {"text": "Information Technology Infrastructure Library", "label": "B"}, {"text": "Integrated Technology Information Lifecycle", "label": "C"}, {"text": "Information Technical Integration Layer", "label": "D"}]', 'B', 'ITIL signifie Information Technology Infrastructure Library', NULL, 'easy', 1, 0, '2026-04-19 00:08:15.289', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce69001m54lrkjwiodb3', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Quel est le concept central d''ITIL 4 ?', '[{"text": "Le processus", "label": "A"}, {"text": "La chaine de valeur des services (SVS)", "label": "B"}, {"text": "Le catalogue de services", "label": "C"}, {"text": "Le SLA", "label": "D"}]', 'B', 'Le Service Value System (SVS) est le concept central d''ITIL 4', NULL, 'medium', 1, 1, '2026-04-19 00:08:15.297', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce6g001n54lrqkfa8ris', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Combien de principes directeurs sont definis dans ITIL 4 ?', '[{"text": "5", "label": "A"}, {"text": "7", "label": "B"}, {"text": "9", "label": "C"}, {"text": "4", "label": "D"}]', 'B', 'ITIL 4 definit 7 principes directeurs (guiding principles)', NULL, 'medium', 1, 2, '2026-04-19 00:08:15.304', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce6r001o54lr9l1hs3z8', NULL, 'cmo50ce5t001k54lrax28rgw4', 'TRUE_FALSE', 'Un service en ITIL est un moyen de delivrer de la valeur aux clients en facilitant les resultats souhaites.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'C''est la definition ITIL d''un service : faciliter la co-creation de valeur', NULL, 'easy', 1, 3, '2026-04-19 00:08:15.315', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce6x001p54lra4af5as1', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Quelle pratique ITIL gere les interruptions non planifiees de service ?', '[{"text": "Problem Management", "label": "A"}, {"text": "Incident Management", "label": "B"}, {"text": "Change Enablement", "label": "C"}, {"text": "Service Request Management", "label": "D"}]', 'B', 'L''Incident Management restaure le fonctionnement normal du service le plus rapidement possible', NULL, 'medium', 1, 4, '2026-04-19 00:08:15.321', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce74001q54lrjtrolwo0', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Quelle est la difference entre un incident et un probleme en ITIL ?', '[{"text": "Aucune difference", "label": "A"}, {"text": "Un incident est une interruption, un probleme est la cause racine", "label": "B"}, {"text": "Un probleme est plus grave", "label": "C"}, {"text": "Un incident est planifie", "label": "D"}]', 'B', 'Un incident est un evenement impactant le service, un probleme est la cause sous-jacente d''un ou plusieurs incidents', NULL, 'medium', 1, 5, '2026-04-19 00:08:15.328', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce7a001r54lr1ras45hk', NULL, 'cmo50ce5t001k54lrax28rgw4', 'MULTIPLE_CHOICE', 'Quels sont des principes directeurs ITIL 4 ?', '[{"text": "Focus on value", "label": "A"}, {"text": "Start where you are", "label": "B"}, {"text": "Maximize profit", "label": "C"}, {"text": "Keep it simple and practical", "label": "D"}]', 'A,B,D', 'Focus on value, Start where you are et Keep it simple sont des principes ITIL 4. Maximize profit n''en est pas un', NULL, 'hard', 1, 6, '2026-04-19 00:08:15.334', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce7l001s54lry5d4tv4i', NULL, 'cmo50ce5t001k54lrax28rgw4', 'SINGLE_CHOICE', 'Le CMDB (Configuration Management Database) stocke :', '[{"text": "Les mots de passe", "label": "A"}, {"text": "Les informations sur les elements de configuration et leurs relations", "label": "B"}, {"text": "Les tickets d''incident", "label": "C"}, {"text": "Les contrats fournisseurs", "label": "D"}]', 'B', 'Le CMDB contient les informations sur les CI (Configuration Items) et leurs relations', NULL, 'medium', 1, 7, '2026-04-19 00:08:15.345', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce82001u54lr2wqna02u', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Quelle est la duree recommandee d''un Sprint en Scrum ?', '[{"text": "1 mois maximum", "label": "A"}, {"text": "3 mois", "label": "B"}, {"text": "6 mois", "label": "C"}, {"text": "1 semaine exactement", "label": "D"}]', 'A', 'Un Sprint dure entre 1 et 4 semaines, avec un maximum d''un mois', NULL, 'easy', 1, 0, '2026-04-19 00:08:15.362', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce8b001v54lrmk0nl2re', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Qui est responsable de maximiser la valeur du produit ?', '[{"text": "Le Scrum Master", "label": "A"}, {"text": "Le Product Owner", "label": "B"}, {"text": "L''equipe de developpement", "label": "C"}, {"text": "Le manager", "label": "D"}]', 'B', 'Le Product Owner est responsable de maximiser la valeur du produit et de gerer le Product Backlog', NULL, 'easy', 1, 1, '2026-04-19 00:08:15.371', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce8j001w54lrzzri9hgn', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Quel est le role principal du Scrum Master ?', '[{"text": "Gerer l''equipe", "label": "A"}, {"text": "Ecrire le code", "label": "B"}, {"text": "Faciliter le processus Scrum et supprimer les obstacles", "label": "C"}, {"text": "Definir les exigences", "label": "D"}]', 'C', 'Le Scrum Master est un servant-leader qui facilite Scrum et aide a supprimer les impediments', NULL, 'easy', 1, 2, '2026-04-19 00:08:15.38', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce8r001x54lrai7hit0u', NULL, 'cmo50ce7v001t54lrc6acura4', 'TRUE_FALSE', 'Le Daily Scrum doit durer exactement 15 minutes.', '[{"text": "Vrai", "label": "A"}, {"text": "Faux", "label": "B"}]', 'A', 'Le Daily Scrum est un evenement timeboxe de 15 minutes pour l''equipe de developpement', NULL, 'easy', 1, 3, '2026-04-19 00:08:15.387', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce8x001y54lrfsw3u1w7', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Quels sont les trois piliers de Scrum ?', '[{"text": "Planification, execution, cloture", "label": "A"}, {"text": "Transparence, inspection, adaptation", "label": "B"}, {"text": "Vitesse, qualite, cout", "label": "C"}, {"text": "Communication, collaboration, confiance", "label": "D"}]', 'B', 'Les trois piliers empiriques de Scrum sont : transparence, inspection et adaptation', NULL, 'medium', 1, 4, '2026-04-19 00:08:15.393', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce92001z54lrx88uzo5e', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Qu''est-ce que la Definition of Done (DoD) ?', '[{"text": "La date de fin du sprint", "label": "A"}, {"text": "Un ensemble de criteres que chaque increment doit satisfaire pour etre considere comme termine", "label": "B"}, {"text": "La liste des taches du sprint", "label": "C"}, {"text": "Le budget restant", "label": "D"}]', 'B', 'La DoD est un accord formel sur les criteres de qualite pour chaque increment', NULL, 'medium', 1, 5, '2026-04-19 00:08:15.398', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce98002054lrdeehkx6a', NULL, 'cmo50ce7v001t54lrc6acura4', 'MULTIPLE_CHOICE', 'Quels sont des evenements Scrum ?', '[{"text": "Sprint Planning", "label": "A"}, {"text": "Sprint Review", "label": "B"}, {"text": "Weekly Status Meeting", "label": "C"}, {"text": "Sprint Retrospective", "label": "D"}]', 'A,B,D', 'Sprint Planning, Sprint Review et Sprint Retrospective sont des evenements Scrum. Le Weekly Status Meeting n''en est pas un', NULL, 'medium', 1, 6, '2026-04-19 00:08:15.404', true, '{}');
INSERT INTO public.questions VALUES ('cmo50ce9g002154lrexvv9yfu', NULL, 'cmo50ce7v001t54lrc6acura4', 'SINGLE_CHOICE', 'Qui peut annuler un Sprint ?', '[{"text": "Le Scrum Master", "label": "A"}, {"text": "L''equipe de developpement", "label": "B"}, {"text": "Le Product Owner", "label": "C"}, {"text": "Le stakeholder", "label": "D"}]', 'C', 'Seul le Product Owner a l''autorite d''annuler un Sprint si l''objectif devient obsolete', NULL, 'hard', 1, 7, '2026-04-19 00:08:15.412', true, '{}');
